const API_URL = '/api/products';

export const getProducts = async () => {
  const res = await fetch(API_URL);
  if (!res.ok) throw new Error('Не удалось загрузить меню');
  return res.json();
};

export const createProduct = async (data) => {
  const res = await fetch(API_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data)
  });
  if (!res.ok) throw new Error('Не удалось создать товар');
  return res.json();
};

export const updateProduct = async (id, data) => {
  const res = await fetch(`${API_URL}/${id}`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data)
  });
  if (!res.ok) throw new Error('Не удалось обновить товар');
  return res.json();
};

export const deleteProduct = async (id) => {
  console.log(`→ DELETE запрос на /api/products/${id}`);

  try {
    const response = await fetch(`${API_URL}/${id}`, {
      method: 'DELETE',
      headers: {
        'Content-Type': 'application/json'
      }
    });

    console.log(`← DELETE статус: ${response.status}`);

    if (!response.ok) {
      let errorText = '';
      try {
        errorText = await response.text();
      } catch {}
      console.error('Ошибка сервера при удалении:', response.status, errorText);
      throw new Error(`Удаление не удалось: ${response.status} ${errorText}`);
    }

    // 204 — успешное удаление без тела ответа
    console.log('Удаление успешно (204)');
    return true;
  } catch (err) {
    console.error('Ошибка при выполнении DELETE:', err);
    throw err;
  }
};
